func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()

	// Compile the script once before iterating to improve performance.
	// This prevents re-parsing the syntax for every single item.
	program, err := vm.Compile(conditionScript)
	if err != nil {
		return nil, fmt.Errorf("script compilation error: %w", err)
