package main

import (
	"time"

	"github.com/robertkrimen/otto"
)

// FilterItems filters a slice of maps based on a JavaScript condition.
// Security Fixes:
// 1. Moves otto.New() outside the loop to prevent resource exhaustion (Memory/CPU DoS).
// 2. Compiles the script once outside the loop for efficiency.
// 3. Implements a timeout mechanism using vm.Interrupt to prevent infinite loops (CPU DoS).
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	vm := otto.New()

	// Compile the script once to avoid re-parsing on every iteration
	script, err := vm.Compile("", conditionScript)
	if err != nil {
		return nil, err
	}

	result := make([]map[string]interface{}, 0, len(items))

	// Define a safe timeout for script execution to prevent infinite loops
	const scriptTimeout = 5 * time.Second

	for _, item := range items {
		// Inject the current item into the VM
		if err := vm.Set("item", item); err != nil {
			return nil, err
		}

		// Setup goroutine to handle execution with timeout
		done := make(chan struct{})
		timer := time.NewTimer(scriptTimeout)

		var val otto.Value
		var runErr error

		go func() {
			defer close(done)
			val, runErr = vm.Run(script)
		}()

		// Wait for completion or timeout
		select {
		case <-done:
			// Clean up timer if it hasn't fired
			if !timer.Stop() {
				select {
				case <-timer.C:
				default:
				}
			}
		case <-timer.C:
			// Trigger interrupt on the VM
			vm.Interrupt <- struct{}{}
			// Ensure the goroutine finishes before we return
			<-done
			return nil, &ScriptTimeoutError{Item: item}
		}

		if runErr != nil {
			return nil, runErr
		}

		boolResult, err := val.ToBoolean()
		if err != nil {
			return nil, err
		}

		if boolResult {
			result = append(result, item)
		}
	}

	return result, nil
}

type ScriptTimeoutError struct {
	Item map[string]interface{}
}

func (e *ScriptTimeoutError) Error() string {
	return "script execution timed out"
}

