package main

import (
	"fmt"

	"github.com/robertkrimen/otto"
)

// FilterItems iterates through the provided slice of data items and filters them
// based on a JavaScript condition script.
//
// Parameters:
//   - conditionScript: A string containing JavaScript code that evaluates to a boolean.
//     The current item is accessible via the global variable 'item'.
//   - items: A slice of maps containing the data to filter.
//
// Returns:
//   - A slice of items that satisfy the condition.
//   - An error if the script execution fails or returns a non-boolean result.
func FilterItems(conditionScript string, items []map[string]interface{}) ([]map[string]interface{}, error) {
	// Create a single VM instance. Reusing the VM is more efficient than creating one per item,
	// as the script execution context is isolated per Run call regarding variable mutations.
	vm := otto.New()
	var filtered []map[string]interface{}

	for _, item := range items {
		// Inject the current item into the JavaScript environment as 'item'
		if err := vm.Set("item", item); err != nil {
			return nil, fmt.Errorf("failed to set 'item' variable: %w", err)
		}

		// Execute the condition script
		val, err := vm.Run(conditionScript)
		if err != nil {
			return nil, fmt.Errorf("script execution error: %w", err)
		}

		// Convert the JavaScript result to a Go boolean
		result, err := val.ToBoolean()
		if err != nil {
			return nil, fmt.Errorf("result conversion error (script must return boolean): %w", err)
		}

		// If the condition is true, add the original item to the result slice
		if result {
			filtered = append(filtered, item)
		}
	}

	return filtered, nil
}

func main() {
	// Example usage of FilterItems

	// 1. Prepare the data
	items := []map[string]interface{}{
		{"name": "Alice", "age": 25, "role": "admin", "active": true},
		{"name": "Bob", "age": 17, "role": "user", "active": false},
		{"name": "Charlie", "age": 30, "role": "manager", "active": true},
		{"name": "Dave", "age": 15, "role": "admin", "active": true},
	}

	// 2. Define the filtering condition
	// Logic: Must be an admin (role === 'admin') AND active (active === true) AND an adult (age >= 18)
	// Note: Otto handles type coercion loosely, but strict comparison is safer.
	script := "item.role === 'admin' && item.active === true && item.age >= 18"

	// 3. Execute the filter
	filteredItems, err := FilterItems(script, items)
	if err != nil {
		fmt.Printf("Error filtering items: %v\n", err)
		return
	}

	// 4. Output results
	fmt.Println("Filtered Items (Admins, Active, Age >= 18):")
	for _, item := range filteredItems {
		fmt.Printf("- %s (Age: %d, Role: %s)\n", item["name"], item["age"], item["role"])
	}
}

